142	static int index_has_unmerged_entries(struct index_state *istate)
143	{
144		int i;
145		for (i = 0; i < istate->cache_nr; i++) {
146			if (ce_stage(istate->cache[i]))
147				return 1;
148		}
149	
150		return 0;
151	}
152	
153	int is_sparse_index_allowed(struct index_state *istate, int flags)
154	{
155		struct repo_config_values *cfg = repo_config_values(the_repository);
156	
157		if (!cfg->apply_sparse_checkout || !cfg->core_sparse_checkout_cone)
158			return 0;
159	
160		if (!(flags & SPARSE_INDEX_MEMORY_ONLY)) {
161			int test_env;
162	
163			/*
164			 * The sparse index is not (yet) integrated with a split index.
165			 */
166			if (istate->split_index || git_env_bool("GIT_TEST_SPLIT_INDEX", 0))
167				return 0;
168			/*
169			 * The GIT_TEST_SPARSE_INDEX environment variable triggers the
170			 * index.sparse config variable to be on.
171			 */
172			test_env = git_env_bool("GIT_TEST_SPARSE_INDEX", -1);
173			if (test_env >= 0)
174				set_sparse_index_config(istate->repo, test_env);
175	
176			/*
177			 * Only convert to sparse if index.sparse is set.
178			 */
179			prepare_repo_settings(istate->repo);
180			if (!istate->repo->settings.sparse_index)
181				return 0;
182		}
183	
184		if (init_sparse_checkout_patterns(istate))
185			return 0;
186	
187		/*
188		 * We need cone-mode patterns to use sparse-index. If a user edits
189		 * their sparse-checkout file manually, then we can detect during
190		 * parsing that they are not actually using cone-mode patterns and
191		 * hence we need to abort this conversion _without error_. Warnings
192		 * already exist in the pattern parsing to inform the user of their
193		 * bad patterns.
194		 */
195		if (!istate->sparse_checkout_patterns->use_cone_patterns)
196			return 0;
197	
198		return 1;
199	}
200	
201	int convert_to_sparse(struct index_state *istate, int flags)
202	{
203		/*
204		 * If the index is already sparse, empty, or otherwise
205		 * cannot be converted to sparse, do not convert.
206		 */
207		if (istate->sparse_index == INDEX_COLLAPSED || !istate->cache_nr ||
208		    !is_sparse_index_allowed(istate, flags))
209			return 0;
210	
211		/*
212		 * If we are purposefully collapsing a full index, then don't give
213		 * advice when it is expanded later.
214		 */
215		give_advice_on_expansion = 0;
216	
217		/*
218		 * NEEDSWORK: If we have unmerged entries, then stay full.
219		 * Unmerged entries prevent the cache-tree extension from working.
220		 */
221		if (index_has_unmerged_entries(istate))
222			return 0;
223	
224		if (!cache_tree_fully_valid(istate->cache_tree)) {
225			/* Clear and recompute the cache-tree */
226			cache_tree_free(&istate->cache_tree);
227	
228			/*
229			 * Silently return if there is a problem with the cache tree update,
230			 * which might just be due to a conflict state in some entry.
231			 *
232			 * This might create new tree objects, so be sure to use
233			 * WRITE_TREE_MISSING_OK.
234			 */
235			if (cache_tree_update(istate, WRITE_TREE_MISSING_OK))
236				return 0;
237		}
238	
239		remove_fsmonitor(istate);
240	
241		trace2_region_enter("index", "convert_to_sparse", istate->repo);
242		istate->cache_nr = convert_to_sparse_rec(istate,
243							 0, 0, istate->cache_nr,
244							 "", 0, istate->cache_tree);
245	
246		/* Clear and recompute the cache-tree */
247		cache_tree_free(&istate->cache_tree);
248		cache_tree_update(istate, 0);
249	
250		istate->fsmonitor_has_run_once = 0;
251		ewah_free(istate->fsmonitor_dirty);
252		istate->fsmonitor_dirty = NULL;
253		FREE_AND_NULL(istate->fsmonitor_last_update);
254	
255		istate->sparse_index = INDEX_COLLAPSED;
256		trace2_region_leave("index", "convert_to_sparse", istate->repo);
257		return 0;
258	}
259	
260	static void set_index_entry(struct index_state *istate, int nr, struct cache_entry *ce)
261	{
262		ALLOC_GROW(istate->cache, nr + 1, istate->cache_alloc);
263	
264		istate->cache[nr] = ce;
265		add_name_hash(istate, ce);
266	}
267	
268	static int add_path_to_index(const struct object_id *oid,
269				     struct strbuf *base, const char *path,
270				     unsigned int mode, void *context)
271	{
272		struct modify_index_context *ctx = (struct modify_index_context *)context;
273		struct cache_entry *ce;
274		size_t len = base->len;
275	
276		if (S_ISDIR(mode)) {
277			int dtype;
278			size_t baselen = base->len;
279			if (!ctx->pl)
280				return READ_TREE_RECURSIVE;
281	
282			/*
283			 * Have we expanded to a point outside of the sparse-checkout?
284			 *
285			 * Artificially pad the path name with a slash "/" to
286			 * indicate it as a directory, and add an arbitrary file
287			 * name ("-") so we can consider base->buf as a file name
288			 * to match against the cone-mode patterns.
289			 *
290			 * If we compared just "path", then we would expand more
291			 * than we should. Since every file at root is always
292			 * included, we would expand every directory at root at
293			 * least one level deep instead of using sparse directory
294			 * entries.
295			 */
296			strbuf_addstr(base, path);
297			strbuf_add(base, "/-", 2);
298	
299			if (path_matches_pattern_list(base->buf, base->len,
300						      NULL, &dtype,
301						      ctx->pl, ctx->write)) {
302				strbuf_setlen(base, baselen);
303				return READ_TREE_RECURSIVE;
304			}
305	
306			/*
307			 * The path "{base}{path}/" is a sparse directory. Create the correct
308			 * name for inserting the entry into the index.
309			 */
310			strbuf_setlen(base, base->len - 1);
311		} else {
312			strbuf_addstr(base, path);
313		}
314	
315		ce = make_cache_entry(ctx->write, mode, oid, base->buf, 0, 0);
316		ce->ce_flags |= CE_SKIP_WORKTREE | CE_EXTENDED;
317		set_index_entry(ctx->write, ctx->write->cache_nr++, ce);
318	
319		strbuf_setlen(base, len);
320		return 0;
321	}
322	
323	void expand_index(struct index_state *istate, struct pattern_list *pl)
324	{
325		int i;
326		struct index_state *full;
327		struct strbuf base = STRBUF_INIT;
328		const char *tr_region;
329		struct modify_index_context ctx;
330	
331		/*
332		 * If the index is already full, then keep it full. We will convert
333		 * it to a sparse index on write, if possible.
334		 */
335		if (istate->sparse_index == INDEX_EXPANDED)
336			return;
337	
338		/*
339		 * If our index is sparse, but our new pattern set does not use
340		 * cone mode patterns, then we need to expand the index before we
341		 * continue. A NULL pattern set indicates a full expansion to a
342		 * full index.
343		 */
344		if (pl && !pl->use_cone_patterns) {
345			pl = NULL;
346		} else {
347			/*
348			 * We might contract file entries into sparse-directory
349			 * entries, and for that we will need the cache tree to
350			 * be recomputed.
351			 */
352			cache_tree_free(&istate->cache_tree);
353	
354			/*
355			 * If there is a problem creating the cache tree, then we
356			 * need to expand to a full index since we cannot satisfy
357			 * the current request as a sparse index.
358			 */
359			if (cache_tree_update(istate, 0))
360				pl = NULL;
361		}
362	
363		if (!pl && give_advice_on_expansion) {
364			give_advice_on_expansion = 0;
365			advise_if_enabled(ADVICE_SPARSE_INDEX_EXPANDED,
366					  _(ADVICE_MSG));
367		}
368	
369		/*
370		 * A NULL pattern set indicates we are expanding a full index, so
371		 * we use a special region name that indicates the full expansion.
372		 * This is used by test cases, but also helps to differentiate the
373		 * two cases.
374		 */
375		tr_region = pl ? "expand_index" : "ensure_full_index";
376		trace2_region_enter("index", tr_region, istate->repo);
377	
378		/* initialize basics of new index */
379		full = xcalloc(1, sizeof(struct index_state));
380		memcpy(full, istate, sizeof(struct index_state));
381	
382		/*
383		 * This slightly-misnamed 'full' index might still be sparse if we
384		 * are only modifying the list of sparse directories. This hinges
385		 * on whether we have a non-NULL pattern list.
386		 */
387		full->sparse_index = pl ? INDEX_PARTIALLY_SPARSE : INDEX_EXPANDED;
388	
389		/* then change the necessary things */
390		full->cache_alloc = (3 * istate->cache_alloc) / 2;
391		full->cache_nr = 0;
392		ALLOC_ARRAY(full->cache, full->cache_alloc);
393	
394		ctx.write = full;
395		ctx.pl = pl;
396	
397		for (i = 0; i < istate->cache_nr; i++) {
398			struct cache_entry *ce = istate->cache[i];
399			struct tree *tree;
400			struct pathspec ps;
401			int dtype;
402	
403			if (!S_ISSPARSEDIR(ce->ce_mode)) {
404				set_index_entry(full, full->cache_nr++, ce);
405				continue;
406			}
407	
408			/* We now have a sparse directory entry. Should we expand? */
409			if (pl &&
410			    path_matches_pattern_list(ce->name, ce->ce_namelen,
411						      NULL, &dtype,
412						      pl, istate) == NOT_MATCHED) {
413				set_index_entry(full, full->cache_nr++, ce);
414				continue;
415			}
416	
417			if (!(ce->ce_flags & CE_SKIP_WORKTREE))
418				warning(_("index entry is a directory, but not sparse (%08x)"),
419					ce->ce_flags);
420	
421			/* recursively walk into cd->name */
422			tree = lookup_tree(istate->repo, &ce->oid);
423	
424			memset(&ps, 0, sizeof(ps));
425			ps.recursive = 1;
426			ps.has_wildcard = 1;
427			ps.max_depth = -1;
428	
429			strbuf_setlen(&base, 0);
430			strbuf_add(&base, ce->name, strlen(ce->name));
431	
432			read_tree_at(istate->repo, tree, &base, 0, &ps,
433				     add_path_to_index, &ctx);
434	
435			/* free directory entries. full entries are re-used */
436			discard_cache_entry(ce);
437		}
438	
439		/* Copy back into original index. */
440		memcpy(&istate->name_hash, &full->name_hash, sizeof(full->name_hash));
441		memcpy(&istate->dir_hash, &full->dir_hash, sizeof(full->dir_hash));
442		istate->sparse_index = pl ? INDEX_PARTIALLY_SPARSE : INDEX_EXPANDED;
443		free(istate->cache);
444		istate->cache = full->cache;
445		istate->cache_nr = full->cache_nr;
446		istate->cache_alloc = full->cache_alloc;
447		istate->fsmonitor_has_run_once = 0;
448		ewah_free(istate->fsmonitor_dirty);
449		istate->fsmonitor_dirty = NULL;
450		FREE_AND_NULL(istate->fsmonitor_last_update);
451	
452		strbuf_release(&base);
453		free(full);
454	
455		/* Clear and recompute the cache-tree */
456		cache_tree_free(&istate->cache_tree);
457		cache_tree_update(istate, 0);
458	
459		trace2_region_leave("index", tr_region, istate->repo);
460	}
461	
462	void ensure_full_index(struct index_state *istate)
463	{
464		if (!istate)
465			BUG("ensure_full_index() must get an index!");
466		expand_index(istate, NULL);
467	}
468	
469	void ensure_correct_sparsity(struct index_state *istate)
470	{
471		/*
472		 * If the index can be sparse, make it sparse. Otherwise,
473		 * ensure the index is full.
474		 */
475		if (is_sparse_index_allowed(istate, 0))
476			convert_to_sparse(istate, 0);
477		else
478			ensure_full_index(istate);
479	}
480	
481	struct path_found_data {
482		/**
483		 * The path stored in 'dir', if non-empty, corresponds to the most-
484		 * recent path that we checked where:
485		 *
486		 *   1. The path should be a directory, according to the index.
487		 *   2. The path does not exist.
488		 *   3. The parent path _does_ exist. (This may be the root of the
489		 *      working directory.)
490		 */
491		struct strbuf dir;
492		size_t lstat_count;
493	};
494	
495	#define PATH_FOUND_DATA_INIT { \
496		.dir = STRBUF_INIT \
497	}
498	
499	static void clear_path_found_data(struct path_found_data *data)
500	{
501		strbuf_release(&data->dir);
502	}
503	
504	/**
505	 * Return the length of the longest common substring that ends in a
506	 * slash ('/') to indicate the longest common parent directory. Returns
507	 * zero if no common directory exists.
508	 */
509	static size_t max_common_dir_prefix(const char *path1, const char *path2)
510	{
511		size_t common_prefix = 0;
512		for (size_t i = 0; path1[i] && path2[i]; i++) {
513			if (path1[i] != path2[i])
514				break;
515	
516			/*
517			 * If they agree at a directory separator, then add one
518			 * to make sure it is included in the common prefix string.
519			 */
520			if (path1[i] == '/')
521				common_prefix = i + 1;
522		}
523	
524		return common_prefix;
525	}
526	
527	static int path_found(const char *path, struct path_found_data *data)
528	{
529		struct stat st;
530		size_t common_prefix;
531	
532		/*
533		 * If data->dir is non-empty, then it contains a path that doesn't
534		 * exist, including an ending slash ('/'). If it is a prefix of 'path',
535		 * then we can return 0.
536		 */
537		if (data->dir.len && !memcmp(path, data->dir.buf, data->dir.len))
538			return 0;
539	
540		/*
541		 * Otherwise, we must check if the current path exists. If it does, then
542		 * return 1. The cached directory will be skipped until we come across
543		 * a missing path again.
544		 */
545		data->lstat_count++;
546		if (!lstat(path, &st))
547			return 1;
548	
549		/*
550		 * At this point, we know that 'path' doesn't exist, and we know that
551		 * the parent directory of 'data->dir' does exist. Let's set 'data->dir'
552		 * to be the top-most non-existing directory of 'path'. If the first
553		 * parent of 'path' exists, then we will act as though 'path'
554		 * corresponds to a directory (by adding a slash).
555		 */
556		common_prefix = max_common_dir_prefix(path, data->dir.buf);
557	
558		/*
559		 * At this point, 'path' and 'data->dir' have a common existing parent
560		 * directory given by path[0..common_prefix] (which could have length 0).
561		 * We "grow" the data->dir buffer by checking for existing directories
562		 * along 'path'.
563		 */
564	
565		strbuf_setlen(&data->dir, common_prefix);
566		while (1) {
567			/* Find the next directory in 'path'. */
568			const char *rest = path + data->dir.len;
569			const char *next_slash = strchr(rest, '/');
570	
571			/*
572			 * If there are no more slashes, then 'path' doesn't contain a
573			 * non-existent _parent_ directory. Set 'data->dir' to be equal
574			 * to 'path' plus an additional slash, so it can be used for
575			 * caching in the future. The filename of 'path' is considered
576			 * a non-existent directory.
577			 *
578			 * Note: if "{path}/" exists as a directory, then it will never
579			 * appear as a prefix of other callers to this method, assuming
580			 * the context from the clear_skip_worktree... methods. If this
581			 * method is reused, then this must be reconsidered.
582			 */
583			if (!next_slash) {
584				strbuf_addstr(&data->dir, rest);
585				strbuf_addch(&data->dir, '/');
586				break;
587			}
588	
589			/*
590			 * Now that we have a slash, let's grow 'data->dir' to include
591			 * this slash, then test if we should stop.
592			 */
593			strbuf_add(&data->dir, rest, next_slash - rest + 1);
594	
595			/* If the parent dir doesn't exist, then stop here. */
596			data->lstat_count++;
597			if (lstat(data->dir.buf, &st))
598				return 0;
599		}
600	
601		/*
602		 * At this point, 'data->dir' is equal to 'path' plus a slash character,
603		 * and the parent directory of 'path' definitely exists. Moreover, we
604		 * know that 'path' doesn't exist, or we would have returned 1 earlier.
605		 */
606		return 0;
607	}
608	
609	static int clear_skip_worktree_from_present_files_sparse(struct index_state *istate)
610	{
611		struct path_found_data data = PATH_FOUND_DATA_INIT;
612	
613		int path_count = 0;
614		int to_restart = 0;
615	
616		trace2_region_enter("index", "clear_skip_worktree_from_present_files_sparse",
617				    istate->repo);
618		for (int i = 0; i < istate->cache_nr; i++) {
619			struct cache_entry *ce = istate->cache[i];
620	
621			if (ce_skip_worktree(ce)) {
622				path_count++;
623				if (path_found(ce->name, &data)) {
624					if (S_ISSPARSEDIR(ce->ce_mode)) {
625						to_restart = 1;
626						break;
627					}
628					ce->ce_flags &= ~CE_SKIP_WORKTREE;
629				}
630			}
631		}
632	
633		trace2_data_intmax("index", istate->repo,
634				   "sparse_path_count", path_count);
635		trace2_data_intmax("index", istate->repo,
636				   "sparse_lstat_count", data.lstat_count);
637		trace2_region_leave("index", "clear_skip_worktree_from_present_files_sparse",
638				    istate->repo);
639		clear_path_found_data(&data);
640		return to_restart;
641	}
642	
643	static void clear_skip_worktree_from_present_files_full(struct index_state *istate)
644	{
645		struct path_found_data data = PATH_FOUND_DATA_INIT;
646	
647		int path_count = 0;
648	
649		trace2_region_enter("index", "clear_skip_worktree_from_present_files_full",
650				    istate->repo);
651		for (int i = 0; i < istate->cache_nr; i++) {
652			struct cache_entry *ce = istate->cache[i];
653	
654			if (S_ISSPARSEDIR(ce->ce_mode))
655				BUG("ensure-full-index did not fully flatten?");
656	
657			if (ce_skip_worktree(ce)) {
658				path_count++;
659				if (path_found(ce->name, &data))
660					ce->ce_flags &= ~CE_SKIP_WORKTREE;
661			}
662		}
663	
664		trace2_data_intmax("index", istate->repo,
665				   "full_path_count", path_count);
666		trace2_data_intmax("index", istate->repo,
667				   "full_lstat_count", data.lstat_count);
668		trace2_region_leave("index", "clear_skip_worktree_from_present_files_full",
669				    istate->repo);
670		clear_path_found_data(&data);
671	}
672	
673	void clear_skip_worktree_from_present_files(struct index_state *istate)
674	{
675		struct repo_config_values *cfg = repo_config_values(the_repository);
676	
677		if (!cfg->apply_sparse_checkout ||
678		    cfg->sparse_expect_files_outside_of_patterns)
679			return;
680	
681		if (clear_skip_worktree_from_present_files_sparse(istate)) {
682			ensure_full_index(istate);
683			clear_skip_worktree_from_present_files_full(istate);
684		}
685	}
686	
687	/*
688	 * This static global helps avoid infinite recursion between
689	 * expand_to_path() and index_file_exists().
690	 */
691	static int in_expand_to_path = 0;
692	
693	void expand_to_path(struct index_state *istate,
694			    const char *path, size_t pathlen, int icase)
695	{
696		struct strbuf path_mutable = STRBUF_INIT;
697		size_t substr_len;
698	
699		/* prevent extra recursion */
700		if (in_expand_to_path)
701			return;
702	
703		if (!istate->sparse_index)
704			return;
705	
706		in_expand_to_path = 1;
707	
708		/*
709		 * We only need to actually expand a region if the
710		 * following are both true:
711		 *
712		 * 1. 'path' is not already in the index.
713		 * 2. Some parent directory of 'path' is a sparse directory.
714		 */
715	
716		if (index_file_exists(istate, path, pathlen, icase))
717			goto cleanup;
718	
719		strbuf_add(&path_mutable, path, pathlen);
720		strbuf_addch(&path_mutable, '/');
721	
722		/* Check the name hash for all parent directories */
723		substr_len = 0;
724		while (substr_len < pathlen) {
725			char temp;
726			char *replace = strchr(path_mutable.buf + substr_len, '/');
727	
728			if (!replace)
729				break;
730	
731			/* replace the character _after_ the slash */
732			replace++;
733			temp = *replace;
734			*replace = '\0';
735			substr_len = replace - path_mutable.buf;
736			if (index_file_exists(istate, path_mutable.buf,
737					      substr_len, icase)) {
738				/*
739				 * We found a parent directory in the name-hash
740				 * hashtable, because only sparse directory entries
741				 * have a trailing '/' character.  Since "path" wasn't
742				 * in the index, perhaps it exists within this
743				 * sparse-directory.  Expand accordingly.
744				 */
745				ensure_full_index(istate);
746				break;
747			}
748	
749			*replace = temp;
750		}
751	
752	cleanup:
753		strbuf_release(&path_mutable);
754		in_expand_to_path = 0;
755	}
